const { S3Client, GetObjectCommand, PutObjectCommand } = require('@aws-sdk/client-s3');
const path = require('path');

const s3Client = new S3Client();

const OUTPUT_BUCKET = process.env.OUTPUT_BUCKET;
const ALLOWED_SOURCE_BUCKET = process.env.ALLOWED_SOURCE_BUCKET;
const ALLOWED_EXTENSIONS = ['.txt', '.csv', '.json', '.xml', '.pdf'];
const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB limit

exports.handler = async (event) => {
    console.log('Received S3 event:', JSON.stringify(event, null, 2));

    if (!OUTPUT_BUCKET) {
        throw new Error('OUTPUT_BUCKET environment variable is not set');
    }

    if (!ALLOWED_SOURCE_BUCKET) {
        throw new Error('ALLOWED_SOURCE_BUCKET environment variable is not set');
    }

    const results = [];

    for (const record of event.Records) {
        try {
            const sourceBucket = record.s3.bucket.name;
            const rawKey = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
            const fileSize = record.s3.object.size;

            // Validate source bucket matches expected bucket to prevent confused deputy
            if (sourceBucket !== ALLOWED_SOURCE_BUCKET) {
                console.error(`Unauthorized source bucket: ${sourceBucket}`);
                throw new Error('Event from unauthorized source bucket');
            }

            // Validate and sanitize the object key to prevent path traversal
            const sanitizedKey = sanitizeObjectKey(rawKey);
            if (!sanitizedKey) {
                console.error(`Invalid object key rejected: ${rawKey}`);
                throw new Error('Invalid object key');
            }

            // Validate file extension
            const ext = path.extname(sanitizedKey).toLowerCase();
            if (!ALLOWED_EXTENSIONS.includes(ext)) {
                console.error(`Disallowed file extension: ${ext}`);
                throw new Error(`File extension not allowed: ${ext}`);
            }

            // Validate file size from event metadata before downloading
            if (fileSize && fileSize > MAX_FILE_SIZE) {
                console.error(`File too large: ${fileSize} bytes`);
                throw new Error('File exceeds maximum allowed size');
            }

            // Read the file from S3
            const getCommand = new GetObjectCommand({
                Bucket: sourceBucket,
                Key: sanitizedKey,
            });

            const response = await s3Client.send(getCommand);

            // Validate content length from S3 response
            if (response.ContentLength && response.ContentLength > MAX_FILE_SIZE) {
                console.error(`File content too large: ${response.ContentLength} bytes`);
                throw new Error('File content exceeds maximum allowed size');
            }

            const bodyContents = await streamToString(response.Body);

            // Process the file content
            const processedContent = await processDocument(bodyContents, ext);

            // Construct output key using only the basename to prevent path traversal in output
            const baseName = path.basename(sanitizedKey, ext);
            const safeOutputKey = `processed/${baseName}-processed${ext}`;

            // Validate the final output key
            if (!isValidOutputKey(safeOutputKey)) {
                throw new Error('Generated output key is invalid');
            }

            // Save processed results to output bucket
            const putCommand = new PutObjectCommand({
                Bucket: OUTPUT_BUCKET,
                Key: safeOutputKey,
                Body: processedContent,
                ContentType: response.ContentType || 'application/octet-stream',
                ServerSideEncryption: 'aws:kms',
                Metadata: {
                    'source-bucket': sourceBucket,
                    'source-key': sanitizedKey,
                    'processed-at': new Date().toISOString(),
                },
            });

            await s3Client.send(putCommand);

            console.log(`Successfully processed ${sanitizedKey} -> ${safeOutputKey}`);
            results.push({
                sourceKey: sanitizedKey,
                outputKey: safeOutputKey,
                status: 'success',
            });
        } catch (error) {
            console.error(`Error processing record:`, error.message);
            results.push({
                sourceKey: record.s3.object.key,
                status: 'error',
                error: error.message,
            });
        }
    }

    return {
        statusCode: 200,
        body: {
            message: 'Processing complete',
            results,
        },
    };
};

/**
 * Sanitize and validate the S3 object key to prevent path traversal attacks.
 * Returns null if the key is invalid.
 */
function sanitizeObjectKey(key) {
    if (!key || typeof key !== 'string') {
        return null;
    }

    // Reject keys with null bytes
    if (key.includes('\0')) {
        return null;
    }

    // Normalize the path and check for traversal attempts
    const normalized = path.normalize(key);

    // Reject if normalization reveals traversal (e.g., ../ sequences)
    if (normalized.startsWith('..') || normalized.includes('/../') || normalized.startsWith('/')) {
        return null;
    }

    // Reject if the original key contained suspicious patterns
    if (key.includes('..') || key.includes('\\')) {
        return null;
    }

    // Reject excessively long keys
    if (key.length > 1024) {
        return null;
    }

    // Only allow alphanumeric, hyphens, underscores, dots, and forward slashes
    const safePattern = /^[a-zA-Z0-9\-_./]+$/;
    if (!safePattern.test(key)) {
        return null;
    }

    return key;
}

/**
 * Validate the output key is safe to use.
 */
function isValidOutputKey(key) {
    if (!key || typeof key !== 'string') {
        return false;
    }

    // Must start with the expected prefix
    if (!key.startsWith('processed/')) {
        return false;
    }

    // No traversal
    if (key.includes('..') || key.includes('\\')) {
        return false;
    }

    // Reasonable length
    if (key.length > 1024) {
        return false;
    }

    return true;
}

/**
 * Convert a readable stream to a string with size limiting.
 */
async function streamToString(stream) {
    const chunks = [];
    let totalSize = 0;

    for await (const chunk of stream) {
        totalSize += chunk.length;
        if (totalSize > MAX_FILE_SIZE) {
            throw new Error('Stream exceeded maximum allowed size during read');
        }
        chunks.push(chunk);
    }

    return Buffer.concat(chunks).toString('utf-8');
}

/**
 * Process the document content based on file type.
 * This is the core business logic for the document processing pipeline.
 */
async function processDocument(content, extension) {
    const timestamp = new Date().toISOString();

    switch (extension) {
        case '.json': {
            let parsed;
            try {
                parsed = JSON.parse(content);
            } catch (e) {
                throw new Error('Invalid JSON content');
            }
            const processed = {
                originalData: parsed,
                metadata: {
                    processedAt: timestamp,
                    recordCount: Array.isArray(parsed) ? parsed.length : 1,
                    pipeline: 'document-processing',
                },
            };
            return JSON.stringify(processed, null, 2);
        }

        case '.csv': {
            const lines = content.split('\n').filter((line) => line.trim());
            const header = lines[0];
            const processedLines = [
                header + ',processed_at',
                ...lines.slice(1).map((line) => line + ',' + timestamp),
            ];
            return processedLines.join('\n');
        }

        case '.txt': {
            const wordCount = content.split(/\s+/).filter((w) => w.length > 0).length;
            const lineCount = content.split('\n').length;
            const summary = [
                `--- Document Processing Summary ---`,
                `Processed At: ${timestamp}`,
                `Word Count: ${wordCount}`,
                `Line Count: ${lineCount}`,
                `--- Original Content ---`,
                content,
            ].join('\n');
            return summary;
        }

        case '.xml': {
            const wrappedXml = `<?xml version="1.0" encoding="UTF-8"?>
<processedDocument>
  <metadata>
    <processedAt>${timestamp}</processedAt>
    <pipeline>document-processing</pipeline>
  </metadata>
  <originalContent><![CDATA[${content}]]></originalContent>
</processedDocument>`;
            return wrappedXml;
        }

        default: {
            return `Processed at ${timestamp}:\n${content}`;
        }
    }
}